/**
 * Shared scene catalog — referenced from the Hero component's client
 * script (for the live demo) and from the static /demo/[slug] pages
 * (for SEO-indexed example studies).
 *
 * Each scene is a self-contained impact study: location/scope, activity
 * profile with indirect/induced multipliers, and an amount. The level
 * field (state / county / reservation) drives which pool the "New study"
 * button pulls from on the hero.
 */

export type Amount = { v: number; label: string };
export type Activity = {
  id: string;
  label: string;
  indirect: number;
  induced: number;
  jobsPerM: number;
};
export type Scene = {
  level: 'state' | 'county' | 'reservation';
  state?: string;       // 2-digit FIPS, for state/county scenes
  countyFips?: string;  // 5-digit FIPS, for county scenes (highlights the polygon)
  tribalKey?: string;   // lookup key, for reservation scenes
  chip: string;
  sentence: string;
  amount: Amount;
  activity: Activity;
};

